func (s *Server) handleChatStream(w http.ResponseWriter, r *http.Request) {
	var req chatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		jsonResponse(w, http.StatusBadRequest, map[string]any{"error": err.Error()})
		return
	}
	ag := s.resolveAgent(r, req.AgentID)
	if ag == nil {
		jsonResponse(w, http.StatusNotFound, map[string]any{"error": "agent not found"})
		return
	}
	flusher, ok := w.(http.Flusher)
	if !ok {
		jsonResponse(w, http.StatusInternalServerError, map[string]any{"error": "streaming unsupported"})
		return
	}
	uid := s.effectiveUserID(r)
	if uid == "" {
		jsonResponse(w, http.StatusUnauthorized, map[string]any{"error": "unauthorized"})
		return
	}
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	// 鍑昏触 nginx / Cloudflare 瀵归暱瀵垮懡鍝嶅簲鐨勭紦鍐诧紱
	// agent 寰幆浠ヤ汉绫绘墦瀛楅€熷害鍙戝嚭鍧楋紝鎴戜滑甯屾湜瀹冧滑绔嬪嵆鍦ㄧ嚎璺笂浼犺緭锛?	// 鑰屼笉鏄繚鎸佸埌鍝嶅簲鍏抽棴銆?	w.Header().Set("X-Accel-Buffering", "no")
	flusher.Flush()
	atts := req.allAttachments()
	imageURLs := req.inlineImageURLs()
	msgText := req.Message
	if !req.preMaterialized() {
		projectID := s.resolveSessionProject(r.Context(), r, ag.Name(), req.SessionID)
		paths := ag.WriteSessionAttachments(r.Context(), req.SessionID, projectID, atts)
		msgText = annotateMessageWithAttachments(req.Message, paths)
	}

	// 鍦ㄥ惎鍔?agent 涔嬪墠璁㈤槄 hub锛岃繖鏍锋垜浠氨涓嶄細涓庣涓€涓彂鍑虹殑浜嬩欢绔炰簤銆?	// hub 缂撳啿杩涜涓殑浜嬩欢锛屽洜姝?emitEvent 鐨勫垎鍙戝嵆浣挎垜浠秷鑰楃紦鎱篃姘歌繙涓嶄細闃诲銆?	hub := s.chatEventHub()
	agentID := ag.Name()
	sub, unsubscribe := hub.Subscribe(uid, agentID, req.SessionID)
	defer unsubscribe()

	// 浠庤姹備腑鍒嗙 agent 鐨?ctx锛氬綋娴忚鍣ㄦ爣绛鹃〉鏂紑杩炴帴锛堝埛鏂般€佸叧闂€佺綉缁滄姈鍔級鏃讹紝
	// 鎴戜滑甯屾湜 agent 缁х画杩愯锛屼互渚垮叾宸蹭粯璐圭殑 LLM 璋冪敤瀹屾垚骞朵笖鍥炲璁板綍鍦?session_events 涓€?	// 15 鍒嗛挓鐨勪笂闄愭槸鍞竴鍙互鏉€姝诲畠鐨勫洜绱犮€?	agentCtx, cancel := context.WithTimeout(context.WithoutCancel(r.Context()), agentTurnTimeout)
	// cancel 娲诲湪 handler 涓婏紝鑰屼笉鏄?agent goroutine 涓婏細褰撴枩鏉犲懡浠?	// 鎺掗槦涓€涓欢缁椂锛屾垜浠湪 HandleMessage 杩斿洖涔嬪悗淇濇寔 SSE 鎵撳紑锛?	// 鑰屽唴閮ㄤ綔鐢ㄥ煙鐨?cancel 浼氬湪寤剁画鐨勪簨浠跺埌杈炬 handler 鐨勫畨鍏ㄧ綉妫€鏌ヤ箣鍓嶆媶闄?agentCtx銆?	defer cancel()
	agentCtx = agent.ContextWithStream(agentCtx, nil, s.dataStore, hub, uid, agentID, req.SessionID)

	agentDone := make(chan struct{})
	go func() {
		defer close(agentDone)
		// events 鍙傛暟淇濇寔涓?nil 鈥?emitEvent 鐜板湪閫氳繃涓婇潰闄勫姞鐨?		// streamCtx 鎵囧嚭锛坧ersist + hub锛夈€傛 handler 涓嶅啀闇€瑕佹棫鐨勯€氶亾璺緞銆?		_ = ag.HandleWebChatStream(agentCtx, req.SessionID, req.ProjectID, uid, msgText, imageURLs, req.Params, nil)
	}()

	// Heartbeat 闃叉浠ｇ悊锛坣ginx 60s 榛樿銆丆loudflare 100s銆丒LB 60s锛?	// 鍦?agent 姝ｅ湪鎬濊€冧絾灏氭湭鍙戝嚭鍐呭鏃舵潃姝荤┖闂茬殑 SSE 杩炴帴銆?	keepalive := time.NewTicker(30 * time.Second)
	defer keepalive.Stop()

	clientGone := r.Context().Done()
	// turnPending 鍦ㄦ枩鏉犲懡浠?handler 鎶ュ憡瀹冮€氳繃 bus.Inbound 鎺掗槦浜?	// 涓€涓欢缁紙`turn_pending` 浜嬩欢锛夋椂鎵撳紑銆?	// POST goroutine 鐨?HandleMessage 宸茬粡杩斿洖锛屼絾鐪熸鐨勫洖澶嶄粛鍦?	// 涓嶅悓鐨?goroutine 涓?10-15 绉掑 鈥?鎴戜滑淇濇寔 SSE 鎵撳紑锛?	// 浠ヤ究娴忚鍣ㄧ殑鎵撳瓧鎸囩ず鍣ㄤ繚鎸佸彲瑙侊紝寤剁画鐨?content_delta/content 浜嬩欢
	// 娴佸叆鍚屼竴涓繛鎺ャ€傚綋寤剁画鑷繁鐨?`done` 鍒拌揪鏃舵竻闄わ紝
	// 姝ゆ椂寰幆姝ｅ父杩斿洖銆?	turnPending := false
	for {
		select {
		case <-clientGone:
			// 瀹㈡埛绔柇寮€锛沘gent goroutine 鍦ㄥ叾鍒嗙鐨?ctx 涓婄户缁繍琛?			// 骞舵寔涔呭寲瀹冨彂鍑虹殑姣忎釜浜嬩欢銆傞噸鏂板姞杞借亰澶╅〉闈㈢殑鐢ㄦ埛
			// 灏嗛€氳繃 /api/chat/subscribe?since=N 鑾峰彇鍏朵綑鍐呭銆?			return
		case <-agentDone:
			// 绔炰簤锛欻andleMessage 鍚?hub 鍙戝竷 `turn_pending`
			// 骞朵笖 `defer close(agentDone)` 浠庡悓涓€涓?goroutine 瑙﹀彂銆?			// 褰撲袱鑰呴兘灏辩华鏃讹紝Go 鐨?select 闅忔満閫夋嫨锛屽洜姝ゅ嵆浣?			// turn_pending 浜嬩欢鍦?sub 缂撳啿鍖轰腑锛宎gentDone 涔熷彲鑳借幏鑳溿€?			// 棣栧厛鎺掔┖寰呭鐞嗕簨浠朵互浣垮喅绛栫‘瀹氭€с€?		drain:
			for {
				select {
				case env, ok := <-sub:
					if !ok {
						return
					}
					turnPendingEvent, done := forwardChatStreamEvent(w, flusher, env)
					if turnPendingEvent {
						turnPending = true
						continue
					}
					if done {
						return
					}
				default:
					break drain
				}
			}
			if turnPending {
				// HandleMessage 鍦ㄦ帓闃熶竴涓欢缁悗闈欓粯杩斿洖銆?				// 涓嶈鍏抽棴锛涚瓑寰呭欢缁殑 `done` 浜嬩欢閫氳繃 hub銆?				// agentCtx.Done()锛?5 鍒嗛挓瓒呮椂锛夊鏋滃畠姘歌繙涓嶅埌杈惧垯鏄笂闄愩€?				agentDone = nil
				continue
			}
			return
		case <-agentCtx.Done():
			// 涓婇潰 turnPending 璺緞鐨勫畨鍏ㄧ綉锛?			// 鍗充娇娌℃湁 `done` 浜嬩欢鍒拌揪锛屼篃鍦?agent 涓婁笅鏂囩‖瓒呮椂鏃堕€€鍑恒€?			return
		case <-keepalive.C:
			fmt.Fprintf(w, ": ping\n\n")
			flusher.Flush()
		case env, ok := <-sub:
			if !ok {
				return
			}
			turnPendingEvent, done := forwardChatStreamEvent(w, flusher, env)
			if turnPendingEvent {
				turnPending = true
				continue
			}
			if done {
				return
			}
		}
	}
}

func forwardChatStreamEvent(w http.ResponseWriter, flusher http.Flusher, env agent.EventEnvelope) (turnPending bool, done bool) {
	if env.Event.Type == "turn_pending" {
		return true, false
	}
	forwardEvent(w, flusher, env)
	return false, env.Event.Type == "done"
}

// forwardEvent 灏嗕竴涓?EventEnvelope 鍐欏叆 SSE 鍝嶅簲銆?// 鍦?JSON 璐熻浇涓寘鍚?seq 鍐呰仈锛堥櫎浜?SSE `id:` 琛岋級锛?// 浠ヤ究鍓嶇 POST sendChatStream 浣跨敤鐨勫熀浜?fetch 鐨勮В鏋愬櫒
// 鍙互閽堝骞惰鐨?/api/chat/subscribe SSE 杩炴帴杩涜鍘婚噸銆?// 娌℃湁杩欎釜鍘婚噸锛屾瘡涓潡鍦ㄦ椿璺冭疆娆℃湡闂翠細娓叉煋涓ゆ銆?func forwardEvent(w http.ResponseWriter, flusher http.Flusher, env agent.EventEnvelope) {
	payload := map[string]any{
		"seq":  env.Seq,
		"type": env.Event.Type,
	}
	if env.Event.Data != nil {
		payload["data"] = env.Event.Data
	}
	data, _ := json.Marshal(payload)
	if env.Seq >= 0 {
		fmt.Fprintf(w, "id: %d\n", env.Seq)
	}
	fmt.Fprintf(w, "data: %s\n\n", data)
	flusher.Flush()
}

